import {
  clientesRepository,
  type ClientesRepository,
} from "@/repositories/clientes-repository";
import {
  cotizacionesRepository,
  type CotizacionesRepository,
} from "@/repositories/cotizaciones-repository";
import {
  projectsRepository,
  type ProjectsRepository,
} from "@/repositories/projects.repository";
import type {
  ActualizarClienteInput,
  ClienteDetalle,
  ClienteCotizacionResumen,
  ClienteProyectoResumen,
  ClienteResumen,
  CrearClienteInput,
  EstadoClienteResumen,
} from "@/types/cliente";
import type { EntityId } from "@/types/common";

type ClientesServiceDeps = {
  clientesRepository?: ClientesRepository;
  projectsRepository?: ProjectsRepository;
  cotizacionesRepository?: CotizacionesRepository;
};

function extractComuna(direccion: string | null) {
  if (!direccion) {
    return "Sin direccion";
  }

  const parts = direccion
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);

  return parts.at(-1) ?? direccion;
}

function formatRelativeDate(value: string | null) {
  if (!value) {
    return "Sin actividad";
  }

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return "Sin actividad";
  }

  return new Intl.DateTimeFormat("es-CL", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  }).format(date);
}

function resolveEstadoCliente(input: {
  obras: number;
  ultimaGestionAt: string | null;
}): EstadoClienteResumen {
  if (input.obras === 0) {
    return "prospecto";
  }

  if (!input.ultimaGestionAt) {
    return "seguimiento";
  }

  const diffDays =
    (Date.now() - new Date(input.ultimaGestionAt).getTime()) /
    (1000 * 60 * 60 * 24);

  if (diffDays <= 30) {
    return "activo";
  }

  if (diffDays <= 90) {
    return "seguimiento";
  }

  return "inactivo";
}

function buildClienteResumen(input: {
  id: EntityId;
  nombre: string;
  telefono: string | null;
  direccion: string | null;
  creadoEn: string | null;
  actualizadoEn: string | null;
  latestProjectTitle: string | null;
  latestProjectUpdatedAt: string | null;
  latestQuoteDate: string | null;
  obras: number;
}): ClienteResumen {
  const ultimaGestionAt =
    input.latestQuoteDate ??
    input.latestProjectUpdatedAt ??
    input.actualizadoEn ??
    input.creadoEn;

  return {
    id: input.id,
    nombre: input.nombre,
    telefono: input.telefono,
    comuna: extractComuna(input.direccion),
    referencia: input.latestProjectTitle ?? input.direccion ?? "Sin referencia",
    obras: input.obras,
    ultimaGestion: formatRelativeDate(ultimaGestionAt),
    ultimaGestionAt,
    estado: resolveEstadoCliente({
      obras: input.obras,
      ultimaGestionAt,
    }),
  };
}

export function createClientesService(deps: ClientesServiceDeps = {}) {
  const clientesRepo = deps.clientesRepository ?? clientesRepository;
  const projectsRepo = deps.projectsRepository ?? projectsRepository;
  const cotizacionesRepo = deps.cotizacionesRepository ?? cotizacionesRepository;

  function buildProjectsByClientId(
    projects: Awaited<ReturnType<ProjectsRepository["listByOrganizationId"]>>
  ) {
    const projectsByClientId = new Map<string, typeof projects>();

    for (const project of projects) {
      if (project.clienteId === null || project.clienteId === undefined) {
        continue;
      }

      const key = String(project.clienteId);
      const current = projectsByClientId.get(key) ?? [];
      current.push(project);
      projectsByClientId.set(key, current);
    }

    return projectsByClientId;
  }

  return {
    async listResumenByOrganizationId(
      organizationId: EntityId
    ): Promise<ClienteResumen[]> {
      const [clientes, projects, cotizaciones] = await Promise.all([
        clientesRepo.listByOrganizationId(organizationId),
        projectsRepo.listByOrganizationId(organizationId),
        cotizacionesRepo.listByOrganizationId(organizationId),
      ]);

      const projectsByClientId = buildProjectsByClientId(projects);
      const latestQuoteDateByProjectId = new Map<string, string>();

      for (const cotizacion of cotizaciones) {
        if (!cotizacion.proyectoId) {
          continue;
        }

        const key = String(cotizacion.proyectoId);
        const updatedAt = cotizacion.actualizadoEn ?? cotizacion.creadoEn;

        if (!updatedAt) {
          continue;
        }

        const currentLatest = latestQuoteDateByProjectId.get(key);

        if (
          !currentLatest ||
          new Date(updatedAt).getTime() > new Date(currentLatest).getTime()
        ) {
          latestQuoteDateByProjectId.set(key, updatedAt);
        }
      }

      return clientes
        .map((cliente) => {
          const relatedProjects = projectsByClientId.get(String(cliente.id)) ?? [];
          let latestProject = relatedProjects[0] ?? null;
          let latestQuoteDate: string | null = null;

          for (const project of relatedProjects) {
            const projectUpdatedAt = project.actualizadoEn ?? project.creadoEn ?? null;

            if (
              projectUpdatedAt &&
              (!latestProject ||
                new Date(projectUpdatedAt).getTime() >
                  new Date(
                    latestProject.actualizadoEn ?? latestProject.creadoEn ?? 0
                  ).getTime())
            ) {
              latestProject = project;
            }

            const quoteUpdatedAt = latestQuoteDateByProjectId.get(String(project.id));

            if (
              quoteUpdatedAt &&
              (!latestQuoteDate ||
                new Date(quoteUpdatedAt).getTime() >
                  new Date(latestQuoteDate).getTime())
            ) {
              latestQuoteDate = quoteUpdatedAt;
            }
          }

          const ultimaGestionAt =
            latestQuoteDate ??
            latestProject?.actualizadoEn ??
            latestProject?.creadoEn ??
            cliente.actualizadoEn ??
            cliente.creadoEn;
          const obras = relatedProjects.length;

          return buildClienteResumen({
            id: cliente.id,
            nombre: cliente.nombre,
            telefono: cliente.telefono,
            direccion: cliente.direccion,
            creadoEn: cliente.creadoEn,
            actualizadoEn: cliente.actualizadoEn,
            latestProjectTitle: latestProject?.titulo ?? null,
            latestProjectUpdatedAt:
              latestProject?.actualizadoEn ?? latestProject?.creadoEn ?? null,
            latestQuoteDate,
            obras,
          });
        })
        .sort((left, right) => {
          return (
            new Date(right.ultimaGestionAt ?? 0).getTime() -
            new Date(left.ultimaGestionAt ?? 0).getTime()
          );
        });
    },

    async getDetalleById(
      clientId: EntityId,
      organizationId: EntityId
    ): Promise<ClienteDetalle | null> {
      const [cliente, projects, cotizaciones] = await Promise.all([
        clientesRepo.getById(clientId, organizationId),
        projectsRepo.listByOrganizationId(organizationId),
        cotizacionesRepo.listByOrganizationId(organizationId),
      ]);

      if (!cliente) {
        return null;
      }

      const relatedProjects = projects.filter(
        (project) => String(project.clienteId) === String(cliente.id)
      );
      const quotesByProjectId = new Map<string, ClienteCotizacionResumen[]>();

      for (const cotizacion of cotizaciones) {
        if (!cotizacion.proyectoId) {
          continue;
        }

        const project = relatedProjects.find(
          (entry) => String(entry.id) === String(cotizacion.proyectoId)
        );

        if (!project) {
          continue;
        }

        const summary: ClienteCotizacionResumen = {
          id: cotizacion.id,
          codigo: cotizacion.numero ?? `COT-${cotizacion.id}`,
          proyectoId: cotizacion.proyectoId,
          obra: project.titulo,
          estado: cotizacion.estado,
          total: cotizacion.total,
          updatedAt: cotizacion.actualizadoEn ?? cotizacion.creadoEn,
        };
        const key = String(cotizacion.proyectoId);
        const current = quotesByProjectId.get(key) ?? [];

        current.push(summary);
        quotesByProjectId.set(key, current);
      }

      const proyectos: ClienteProyectoResumen[] = relatedProjects
        .map((project) => {
          const projectQuotes = quotesByProjectId.get(String(project.id)) ?? [];
          const latestQuoteAt =
            [...projectQuotes]
              .sort(
                (left, right) =>
                  new Date(right.updatedAt ?? 0).getTime() -
                  new Date(left.updatedAt ?? 0).getTime()
              )[0]?.updatedAt ?? null;

          return {
            id: project.id,
            titulo: project.titulo,
            estado: project.estado,
            cotizaciones: projectQuotes.length,
            ultimaActividadAt:
              latestQuoteAt ?? project.actualizadoEn ?? project.creadoEn,
          };
        })
        .sort(
          (left, right) =>
            new Date(right.ultimaActividadAt ?? 0).getTime() -
            new Date(left.ultimaActividadAt ?? 0).getTime()
        );

      const resumen = buildClienteResumen({
        id: cliente.id,
        nombre: cliente.nombre,
        telefono: cliente.telefono,
        direccion: cliente.direccion,
        creadoEn: cliente.creadoEn,
        actualizadoEn: cliente.actualizadoEn,
        latestProjectTitle: proyectos[0]?.titulo ?? null,
        latestProjectUpdatedAt: proyectos[0]?.ultimaActividadAt ?? null,
        latestQuoteDate:
          [...quotesByProjectId.values()]
            .flat()
            .sort(
              (left, right) =>
                new Date(right.updatedAt ?? 0).getTime() -
                new Date(left.updatedAt ?? 0).getTime()
            )[0]?.updatedAt ?? null,
        obras: relatedProjects.length,
      });

      return {
        cliente,
        resumen,
        proyectos,
        cotizaciones: [...quotesByProjectId.values()]
          .flat()
          .sort(
            (left, right) =>
              new Date(right.updatedAt ?? 0).getTime() -
              new Date(left.updatedAt ?? 0).getTime()
          ),
      };
    },

    async createClient(input: CrearClienteInput) {
      const nombre = input.nombre.trim();

      if (!nombre) {
        throw new Error("El nombre del cliente es obligatorio");
      }

      return clientesRepo.create({
        ...input,
        nombre,
        telefono: input.telefono?.trim() || null,
        direccion: input.direccion?.trim() || null,
        correo: input.correo?.trim().toLowerCase() || null,
      });
    },

    async updateClient(
      clientId: EntityId,
      organizationId: EntityId,
      input: ActualizarClienteInput
    ) {
      const payload: ActualizarClienteInput = {};

      if (input.nombre !== undefined) {
        const nombre = input.nombre.trim();

        if (!nombre) {
          throw new Error("El nombre del cliente es obligatorio");
        }

        payload.nombre = nombre;
      }

      if (input.telefono !== undefined) {
        payload.telefono = input.telefono?.trim() || null;
      }

      if (input.direccion !== undefined) {
        payload.direccion = input.direccion?.trim() || null;
      }

      if (input.correo !== undefined) {
        payload.correo = input.correo?.trim().toLowerCase() || null;
      }

      return clientesRepo.update(clientId, organizationId, payload);
    },
  };
}

export const clientesService = createClientesService();
